268→    /*
269→     * Direct convolution with fused bias + requantize.
270→     * Vectorizes across out_tensor_ch: vqmacc.vx accumulates one input scalar
271→     * against the full transposed weight row (all output channels).
272→     * Processes 2 output pixels at a time, sharing weight loads.
273→     * Eliminates im2col buffer and q32 intermediate buffer.
274→     *
275→     * Register plan:
276→     *   v0-v7  (M8): Accumulator pixel 1 (e32)
277→     *   v8-v15 (M8): Accumulator pixel 2 (e32)
278→     *   v16-v17 (M2): Weight vector load (e8)
279→     */
280→    const int in_tensor_ch = 3;
281→    long i_ker_y, i_ker_x, ch;
282→
283→    const long align_byte = 64;
284→    q7_t *pOut = out_tensor;
285→    long vl;
286→
287→    /* Allocate transposed weight buffer from in_tmp_buf */
288→    q7_t *src2 = (q7_t *)in_tmp_buf;
289→    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);
290→
291→    /* Transpose weights once: from [out_ch x K] to [K x out_ch] */
292→    const long row = out_tensor_ch;
293→    const long col = ker_dim * ker_dim * in_tensor_ch;
294→    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);
295→
296→    /* Total output pixels */
297→    long total_pixels = (long)out_tensor_dim * out_tensor_dim;
298→    long pixel_idx = 0;
299→
300→    /* Process 2 output pixels at a time */
301→    for (; pixel_idx + 1 < total_pixels; pixel_idx += 2)
302→    {
303→        long out_y1 = pixel_idx / out_tensor_dim;
304→        long out_x1 = pixel_idx % out_tensor_dim;
305→        long out_y2 = (pixel_idx + 1) / out_tensor_dim;
306→        long out_x2 = (pixel_idx + 1) % out_tensor_dim;
307→
308→        /* Load bias into accumulators: v0 (pixel1), v8 (pixel2) at e32/M8 */
309→        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
310→        NDS_VEC_VLE32_V(NDS_VEC_V0, bias);
311→        NDS_VEC_VLE32_V(NDS_VEC_V8, bias);
312→
313→        /* Accumulate over all K positions */
314→        for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
315→        {
316→            long in_row1 = out_y1 * stride - pad + i_ker_y;
317→            long in_row2 = out_y2 * stride - pad + i_ker_y;
318→
319→            for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
320→            {
321→                long in_col1 = out_x1 * stride - pad + i_ker_x;
322→                long in_col2 = out_x2 * stride - pad + i_ker_x;
323→                long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
324→
325→                for (ch = 0; ch < in_tensor_ch; ch++)
326→                {
327→                    long k_pos = k_base + ch;
328→
329→                    /* Load transposed weight row into v16 at e8/M2 */
330→                    NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
331→                    NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch);
332→
333→                    /* Get input scalars */
334→                    q7_t a1 = 0, a2 = 0;
335→                    if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
336→                        in_col1 >= 0 && in_col1 < in_tensor_dim)
337→                        a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
338→                    if (in_row2 >= 0 && in_row2 < in_tensor_dim &&
339→                        in_col2 >= 0 && in_col2 < in_tensor_dim)
340→                        a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];
341→
342→                    /* vqmacc.vx: acc[e32/M8] += scalar * wt[e8/M2] */
343→                    NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
344→                    NDS_VEC_VQMACC_VX(NDS_VEC_V8, a2, NDS_VEC_V16);
345→                }
346→            }
347→        }
348→
349→        /* Requantize pixel 1: shift, scale, narrow, clip, store */
350→        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
351→        NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
352→        NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
353→        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
354→        NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
355→        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
356→        NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, 0);
357→        NDS_VEC_VSB_V(NDS_VEC_V0, pOut);
358→        pOut += out_tensor_ch;
359→
360→        /* Requantize pixel 2 */
361→        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
362→        NDS_VEC_VSRA_VX(NDS_VEC_V8, NDS_VEC_V8, pre_rshift);
363→        NDS_VEC_VMUL_VX(NDS_VEC_V8, NDS_VEC_V8, out_scale);
364→        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
365→        NDS_VEC_VNCLIP_WX(NDS_VEC_V8, NDS_VEC_V8, post_rshift);
366→        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
367→        NDS_VEC_VNCLIP_WX(NDS_VEC_V8, NDS_VEC_V8, 0);
368→        NDS_VEC_VSB_V(NDS_VEC_V8, pOut);
369→        pOut += out_tensor_ch;
370→    }
371→
372→    /* Handle the last pixel if total_pixels is odd */
373→    if (pixel_idx < total_pixels)
374→    {
375→        long out_y1 = pixel_idx / out_tensor_dim;
376→        long out_x1 = pixel_idx % out_tensor_dim;
377→
378→        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
379→        NDS_VEC_VLE32_V(NDS_VEC_V0, bias);
380→
381→        for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
382→        {
383→            long in_row1 = out_y1 * stride - pad + i_ker_y;
384→            for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
385→            {
386→                long in_col1 = out_x1 * stride - pad + i_ker_x;
387→                long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
388→                for (ch = 0; ch < in_tensor_ch; ch++)
389→                {
390→                    long k_pos = k_base + ch;
391→                    NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
392→                    NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch);
393→                    q7_t a1 = 0;
394→                    if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
395→                        in_col1 >= 0 && in_col1 < in_tensor_dim)
396→                        a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
397→                    NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
398→                }
399→            }
400→        }
401→
402→        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
403→        NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
404→        NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
405→        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
406→        NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
407→        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
408→        NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, 0);
409→        NDS_VEC_VSB_V(NDS_VEC_V0, pOut);
410→        pOut += out_tensor_ch;
411→    }
412→#else /* NDS_VEC_RVV_VERSION < 1000: fallback to tiling GEMM */
